 1	import React, { FC, useState } from 'react';
 2	
 3	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
 5	import Loading from '@kubevirt-utils/components/Loading/Loading';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { isEmpty } from '@kubevirt-utils/utils/utils';
 8	import { Bullseye, Checkbox, Toolbar, ToolbarContent, ToolbarItem } from '@patternfly/react-core';
 9	import { LogViewer, LogViewerSearch } from '@patternfly/react-log-viewer';
10	
11	type VirtualMachineBasicLogViewerProps = {
12	  data: string[];
13	  isExternal?: boolean;
14	  vmi: V1VirtualMachineInstance;
15	};
16	const VirtualMachineBasicLogViewer: FC<VirtualMachineBasicLogViewerProps> = ({
17	  data,
18	  isExternal = false,
19	  vmi,
20	}) => {
21	  const { t } = useKubevirtTranslation();
22	  const [isTextWrapped, setIsTextWrapped] = useState<boolean>(false);
23	
24	  if (!vmi) {
25	    return <Bullseye>{t('VirtualMachine is not running.')}</Bullseye>;
26	  }
27	
28	  if (isEmpty(data)) {
29	    return (
30	      <Bullseye>
31	        <Loading />
32	      </Bullseye>
33	    );
34	  }
35	
36	  return (
37	    <LogViewer
38	      toolbar={
39	        <Toolbar>
40	          <ToolbarContent>
41	            <ToolbarItem>
42	              <LogViewerSearch minSearchChars={3} placeholder="Search..." />
43	            </ToolbarItem>
44	            <ToolbarItem align={{ default: 'alignRight' }}>
45	              <Checkbox
46	                id="wrap-text-checkbox"
47	                isChecked={isTextWrapped}
48	                label={t('Wrap text')}
49	                onChange={(_event, val) => setIsTextWrapped(val)}
50	              />
51	            </ToolbarItem>
52	            {!isExternal && (
53	              <>
54	                <ToolbarItem variant="separator" />
55	                <ToolbarItem>
56	                  <ExternalLink
57	                    href={`/k8s/ns/${vmi?.metadata?.namespace}/kubevirt.io~v1~VirtualMachine/${vmi?.metadata?.name}/diagnostics/logs/standalone`}
58	                  >
59	                    {t('Open logs in a new window')}
60	                  </ExternalLink>
61	                </ToolbarItem>
62	              </>
63	            )}
64	          </ToolbarContent>
65	        </Toolbar>
66	      }
67	      data={data}
68	      isTextWrapped={isTextWrapped}
69	      scrollToRow={data.length}
70	      theme="dark"
71	    />
72	  );
73	};
74	
75	export default VirtualMachineBasicLogViewer;

